arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 49
$timeout = 600
$interval = 30
$elapsed = 0
$found = $false

while ($elapsed -lt $timeout) {
    # Strategy A: "Copilot's findings"
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" 2>$null | ConvertFrom-Json
    foreach ($r in $reviews) {
        if ($r.body -match "Copilot.s findings") {
            Write-Output "FOUND via Strategy A: review id=$($r.id)"
            Write-Output "Body: $($r.body)"
            $found = $true
            break
        }
        if ($r.body -match "Pull request overview") {
            Write-Output "FOUND via Strategy B: review id=$($r.id)"
            Write-Output "Body: $($r.body)"
            $found = $true
            break
        }
        if ($r.user.login -match "copilot-pull-request-reviewer") {
            Write-Output "FOUND via Strategy C: review id=$($r.id), user=$($r.user.login)"
            Write-Output "Body: $($r.body)"
            $found = $true
            break
        }
    }
    if ($found) { break }

    # Strategy D: Line-level comments from Copilot
    $comments = gh api "/repos/$REPO/pulls/$PR/comments" 2>$null | ConvertFrom-Json
    foreach ($c in $comments) {
        if ($c.user.login -eq "Copilot") {
            Write-Output "FOUND via Strategy D: comment id=$($c.id), user=Copilot"
            Write-Output "Body: $($c.body)"
            $found = $true
            break
        }
    }
    if ($found) { break }

    Write-Output "Poll $([math]::Floor($elapsed/30)+1): No Copilot review yet. Waiting ${interval}s... (elapsed: ${elapsed}s)"
    Start-Sleep -Seconds $interval
    $elapsed += $interval
}

if (-not $found) {
    Write-Output "TIMEOUT: Copilot review not found after ${timeout}s"
}

