$REPO_OWNER = "edburns"
$REPO_NAME = "Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"

# Get thread IDs for both comments
$query = @"
query {
  repository(owner: "$REPO_OWNER", name: "$REPO_NAME") {
    pullRequest(number: 49) {
      reviewThreads(first: 100) {
        nodes {
          id
          isResolved
          comments(first: 1) { nodes { databaseId } }
        }
      }
    }
  }
}
"@

$result = gh api graphql -f "query=$query" 2>&1
$threads = ($result | ConvertFrom-Json).data.repository.pullRequest.reviewThreads.nodes

foreach ($t in $threads) {
    $commentId = $t.comments.nodes[0].databaseId
    if ($commentId -eq 3609606564 -or $commentId -eq 3609606572) {
        if (-not $t.isResolved) {
            Write-Output "Resolving thread $($t.id) for comment $commentId"
            $mutation = "mutation { resolveReviewThread(input: {threadId: `"$($t.id)`"}) { thread { id isResolved } } }"
            gh api graphql -f "query=$mutation" 2>&1
        } else {
            Write-Output "Thread for comment $commentId already resolved"
        }
    }
}

